class QueryStatus(StrictModel):
    complete: bool | None = Field(False, description="Whether the query is still running. Will be true if the query is complete, even if it errored. Either result or error will be set.")
    dashboard_id: int | None = None
    end_time: str | None = Field(None, description="When did the query execution task finish (whether successfully or not).", json_schema_extra={'format': 'date-time'})
    error: bool | None = Field(False, description="If the query failed, this will be set to true. More information can be found in the error_message field.")
    error_message: str | None = None
    expiration_time: str | None = Field(None, json_schema_extra={'format': 'date-time'})
    id_: str = Field(..., validation_alias="id", serialization_alias="id")
    insight_id: int | None = None
    labels: list[str] | None = None
    pickup_time: str | None = Field(None, description="When was the query execution task picked up by a worker.", json_schema_extra={'format': 'date-time'})
    query_async: Literal[True] | None = Field(True, description="ONLY async queries use QueryStatus.")
    query_progress: ClickhouseQueryProgress | None = None
    results: Any | None = None
    start_time: str | None = Field(None, description="When was query execution task enqueued.", json_schema_extra={'format': 'date-time'})
    task_id: str | None = None
    team_id: int

